module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output reg mul_en_out,
    output mul_out
);
output reg mul_en_out;
output reg [15:0] mul_out;
reg [7:0] mul_a_reg;
reg [7:0] mul_b_reg;
reg [15:0] mul_out_reg;
reg [15:0] temp;
reg [7:0] sum;
reg [7:0] carry;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_en_out_reg    <= 0;
        mul_a_reg         <= 0;
        mul_b_reg         <= 0;
        mul_out_reg       <= 0;
        mul_en_out        <= 0;
        for (int i = 0; i < 8; i = i + 1) begin
            sum[i]          <= 0;
            carry[i]        <= 0;
        end
        for (int i = 0; i < 15; i = i + 1) begin
            temp[i]         <= 0;
        end
    end
    else begin
        mul_en_out_reg    <= mul_en_in;
        mul_a_reg         <= mul_a;
        mul_b_reg         <= mul_b;
        mul_en_out        <= mul_en_out_reg[MUL_WIDTH - 1];
        if (mul_en_out_reg[MUL_WIDTH - 1]) begin
            mul_out_reg       <= mul_out_reg + sum[MUL_WIDTH - 2];
        end
        else begin
            mul_out_reg       <= 0;
        end
        for (int i = 0; i < MUL_WIDTH - 1; i = i + 1) begin
            if (carry[i]) begin
                sum[i + 1] <= ~sum[i];
                carry[i] <= 0;
            end
            else begin
                sum[i + 1] <= sum[i];
            end
        end
        if (carry[MUL_WIDTH - 2]) begin
            mul_out_reg <= mul_out_reg + sum[MUL_WIDTH - 2];
        end
        else begin
            mul_out_reg <= mul_out_reg;
        end
    end
end
always @(posedge clk) begin
    for (int i = 0; i < MUL_WIDTH; i = i + 1) begin
        if (mul_b_reg[i] == 1'b1) begin
            temp[i + MUL_WIDTH - 1 : i] <= mul_a_reg;
        end
        else begin
            temp[i + MUL_WIDTH - 1 : i] <= {MUL_WIDTH{1'b0}};
        end
    end
end
endmodule
